const https=require('https');
const out=(m)=>[{json:m}];
const err=(m)=>[{json:{error:m}}];

// 1) parse args (unwrap robuste)
const inp=$('Input').first().json||{};
function fromStr(s){s=String(s).trim();if(s.startsWith('{')){try{return JSON.parse(s);}catch(e){}}return {};}
let raw=(inp.query!==undefined)?inp.query:inp; let a={};
if(typeof raw==='string'){a=fromStr(raw);}
else if(raw&&typeof raw==='object'){
  if(raw.resource!==undefined||raw.agent_id!==undefined||raw.type!==undefined){a=raw;}
  else{const f=Object.values(raw)[0]; a=(typeof f==='string')?fromStr(f):(f&&typeof f==='object'?f:raw);}
}
const resource=String(a.resource||a.kind||'').toLowerCase().trim();
let agent=String(a.agent_id||a.agent||'').trim();
let typ=String(a.type||a.subtype||'').toLowerCase().trim();
let limit=Number(a.limit)||0;
let status=String(a.status||'').trim();
if(agent==='1'||/ubuntu.?2|agent_ubuntu2/i.test(agent))agent='001';
if(agent==='2'||/win/i.test(agent))agent='002';
if(agent==='0'||/manager/i.test(agent))agent='000';

// 2) mappe resource -> path API
let path;
const needAgent=()=>{if(!['000','001','002'].includes(agent))throw 'agent_id requis (000 manager, 001 ubuntu2, 002 windows)';};
try{
  if(resource==='agents'){
    const lim=limit||50;
    path=`/agents?limit=${lim}&select=id,name,ip,status,os.name,os.platform,version,lastKeepAlive,group`;
    if(status)path+=`&status=${encodeURIComponent(status)}`;
  } else if(resource==='inventory'||resource==='syscollector'){
    needAgent();
    const allowed=['packages','ports','processes','netiface','netaddr','hardware','os','hotfixes'];
    if(!typ)typ='packages';
    if(!allowed.includes(typ))return err(`type inventaire invalide '${typ}'. Autorises: ${allowed.join(', ')}`);
    const lim=limit||50;
    path=`/syscollector/${agent}/${typ}?limit=${lim}`;
  } else if(resource==='fim'||resource==='syscheck'){
    needAgent(); const lim=limit||30;
    path=`/syscheck/${agent}?limit=${lim}&sort=-date`;
  } else if(resource==='sca'){
    needAgent(); path=`/sca/${agent}`;
  } else if(resource==='rootcheck'){
    needAgent(); const lim=limit||30;
    path=`/rootcheck/${agent}?limit=${lim}&sort=-date`;
  } else {
    return err(`resource inconnue '${resource}'. Autorisees: agents, inventory, fim, sca, rootcheck (vulnerabilites via get_vulnerabilities).`);
  }
}catch(e){return err(String(e));}

// 3) token
const token=(($('Token').first().json||{}).data||{}).token;
if(!token)return err('token Wazuh introuvable (auth echouee).');

// 4) GET
function rq(opt){return new Promise((res,rej)=>{const r=https.request(opt,x=>{let d='';x.on('data',c=>d+=c);x.on('end',()=>res({code:x.statusCode,body:d}));});r.on('error',rej);r.on('timeout',()=>{r.destroy();rej(new Error('timeout'));});r.end();});}
let r;
try{r=await rq({host:'172.17.0.1',port:55000,path,method:'GET',rejectUnauthorized:false,timeout:9000,headers:{'Authorization':'Bearer '+token}});}
catch(e){return err('GET '+path+' : '+e.message);}
let j;try{j=JSON.parse(r.body);}catch(e){return err('reponse non JSON (http '+r.code+')');}
if(r.code!==200)return err(`http ${r.code}: ${String(r.body).slice(0,160)}`);
const items=(j.data&&j.data.affected_items)||[];
const total=(j.data&&j.data.total_affected_items)!==undefined?j.data.total_affected_items:items.length;

// 5) compaction par resource (limite la taille)
function pick(o,ks){const r={};for(const k of ks){const v=k.split('.').reduce((x,p)=>x&&x[p],o);if(v!==undefined)r[k]=v;}return r;}
let compact=items;
if(resource==='agents')compact=items.map(i=>pick(i,['id','name','ip','status','version','os.name','lastKeepAlive']));
else if(resource==='inventory'&&typ==='packages')compact=items.map(i=>pick(i,['name','version','architecture']));
else if(resource==='inventory'&&typ==='ports')compact=items.map(i=>pick(i,['local.port','protocol','process','state']));
else if(resource==='inventory'&&typ==='processes')compact=items.map(i=>pick(i,['pid','name','cmd','state']));
else if(resource==='inventory'&&typ==='netiface')compact=items.map(i=>pick(i,['name','mac','state']));
else if(resource==='fim')compact=items.map(i=>pick(i,['file','date','perm','uname','size']));
else if(resource==='rootcheck')compact=items.map(i=>pick(i,['log','date','status']));
else if(resource==='sca')compact=items.map(i=>pick(i,['name','policy_id','pass','fail','score']));

return out({resource, type: typ||undefined, agent: agent||undefined, total, count: compact.length, items: compact});
